import React, { useState, useEffect, useContext } from "react";
import API from "../api/api";
import { AuthContext } from "../context/AuthContext";
import { Activity, Code, AlertCircle, CheckCircle2, TerminalSquare } from "lucide-react";

const AnalyticsView = () => {
    const [stats, setStats] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchAnalytics = async () => {
            try {
                const res = await API.get("/submissions/analytics");
                setStats(res.data);
            } catch (error) {
                console.error("Failed to fetch analytics:", error);
            } finally {
                setLoading(false);
            }
        };
        fetchAnalytics();
    }, []);

    if (loading) {
        return <div className="flex items-center justify-center w-full h-full text-muted">Loading Analytics...</div>;
    }

    if (!stats) {
        return <div className="flex items-center justify-center w-full h-full text-error">Failed to load analytics data.</div>;
    }

    const { totalSubmissions, successfulSubmissions, errorSubmissions, languageStats, recentActivity } = stats;
    const successRate = totalSubmissions > 0 ? Math.round((successfulSubmissions / totalSubmissions) * 100) : 0;

    return (
        <div className="flex-col w-full h-full p-6 animate-fade-in" style={{ overflowY: "auto" }}>
            <h2 className="text-2xl font-bold text-primary mb-6 flex items-center gap-2">
                <Activity size={28} /> Student Progress Dashboard
            </h2>

            {/* Top Metrics Cards */}
            <div className="grid grid-cols-4 gap-4 mb-8" style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)" }}>
                <div className="glass-panel p-6 flex flex-col items-center justify-center">
                    <TerminalSquare size={32} className="text-primary mb-2" />
                    <h3 className="text-3xl font-bold">{totalSubmissions}</h3>
                    <p className="text-muted text-sm mt-1">Total Executions</p>
                </div>
                <div className="glass-panel p-6 flex flex-col items-center justify-center">
                    <CheckCircle2 size={32} className="text-success mb-2" />
                    <h3 className="text-3xl font-bold">{successfulSubmissions}</h3>
                    <p className="text-muted text-sm mt-1">Successful Run</p>
                </div>
                <div className="glass-panel p-6 flex flex-col items-center justify-center">
                    <AlertCircle size={32} className="text-error mb-2" />
                    <h3 className="text-3xl font-bold">{errorSubmissions}</h3>
                    <p className="text-muted text-sm mt-1">Error Frequency</p>
                </div>
                <div className="glass-panel p-6 flex flex-col items-center justify-center">
                    <Activity size={32} className="text-primary mb-2" />
                    <h3 className="text-3xl font-bold">{successRate}%</h3>
                    <p className="text-muted text-sm mt-1">Success Rate</p>
                </div>
            </div>

            <div className="grid grid-cols-2 gap-8" style={{ display: "grid", gridTemplateColumns: "1fr 2fr" }}>
                {/* Language Breakdown */}
                <div className="glass-panel p-6">
                    <h3 className="text-lg font-semibold border-b border-gray-700 pb-2 mb-4 flex items-center gap-2">
                        <Code size={20} /> Languages Used
                    </h3>
                    <div className="flex flex-col gap-3">
                        {languageStats.length > 0 ? languageStats.map(lang => (
                            <div key={lang._id} className="flex justify-between items-center p-3 rounded" style={{ background: "rgba(255,255,255,0.05)" }}>
                                <span className="capitalize font-medium">{lang._id}</span>
                                <span className="bg-primary px-3 py-1 rounded-full text-sm">{lang.count} runs</span>
                            </div>
                        )) : <p className="text-muted">No languages used yet.</p>}
                    </div>
                </div>

                {/* Submissions History / Heatmap Alternative */}
                <div className="glass-panel p-6">
                    <h3 className="text-lg font-semibold border-b border-gray-700 pb-2 mb-4 flex items-center gap-2">
                        <Activity size={20} /> Recent Execution History
                    </h3>
                    <div className="flex flex-col gap-2 max-h-64 overflow-y-auto pr-2" style={{ maxHeight: "300px" }}>
                        {recentActivity.length > 0 ? recentActivity.map(session => (
                            <div key={session._id} className="flex justify-between items-center p-3 rounded border border-gray-800" style={{ background: "rgba(0,0,0,0.2)" }}>
                                <div className="flex items-center gap-3">
                                    {session.status === "Success" ? <CheckCircle2 size={16} className="text-success" /> : <AlertCircle size={16} className="text-error" />}
                                    <span className="capitalize text-sm font-medium">{session.language}</span>
                                </div>
                                <div className="text-xs text-muted flex items-center gap-3">
                                    <span className={session.status === "Success" ? "text-success" : "text-error"}>{session.status}</span>
                                    <span>{new Date(session.createdAt).toLocaleString()}</span>
                                </div>
                            </div>
                        )) : <p className="text-muted">No recent activity found.</p>}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default AnalyticsView;

import React, { useState } from "react";
import Editor from "@monaco-editor/react";

const CodeEditor = ({ code, setCode, language, onLanguageChange }) => {
    const handleEditorChange = (value) => {
        setCode(value);
    };

    return (
        <div className="flex-col w-full h-full" style={{ height: "100%", flex: 1 }}>
            <div className="flex justify-between items-center mb-2" style={{ padding: "0 10px" }}>
                <h3 className="text-primary font-semibold" style={{ margin: 0 }}>Code Editor</h3>
                <select
                    className="input-glass"
                    value={language}
                    onChange={(e) => onLanguageChange(e.target.value)}
                    style={{ width: "150px", padding: "0.25rem 0.5rem", height: "auto", backgroundColor: "rgba(0,0,0,0.6)" }}
                >
                    <option value="python">Python</option>
                    <option value="javascript">JavaScript</option>
                    <option value="java">Java</option>
                    <option value="cpp">C++</option>
                    <option value="c">C</option>
                </select>
            </div>
            <div style={{ flex: 1, borderRadius: "8px", overflow: "hidden", border: "1px solid var(--glass-border)" }}>
                <Editor
                    height="100%"
                    theme="vs-dark"
                    language={language}
                    value={code}
                    onChange={handleEditorChange}
                    options={{
                        minimap: { enabled: false },
                        fontSize: 14,
                        padding: { top: 16 },
                        scrollBeyondLastLine: false,
                        smoothScrolling: true,
                        cursorBlinking: "smooth",
                        cursorSmoothCaretAnimation: "on",
                    }}
                />
            </div>
        </div>
    );
};

export default CodeEditor;

