import React, { createContext, useState, useEffect } from "react";
import API from "../api/api";

export const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const userInfo = JSON.parse(localStorage.getItem("user"));
        if (userInfo) {
            setUser(userInfo);
        }
        setLoading(false);
    }, []);

    const login = async (email, password) => {
        try {
            const response = await API.post("/auth/login", { email, password });
            setUser(response.data);
            localStorage.setItem("user", JSON.stringify(response.data));
            return { success: true };
        } catch (error) {
            return {
                success: false,
                message: error.response?.data?.message || "Login failed",
            };
        }
    };

    const register = async (name, email, password, role) => {
        try {
            const response = await API.post("/auth/register", {
                name,
                email,
                password,
                role,
            });
            setUser(response.data);
            localStorage.setItem("user", JSON.stringify(response.data));
            return { success: true };
        } catch (error) {
            return {
                success: false,
                message: error.response?.data?.message || "Registration failed",
            };
        }
    };

    const logout = () => {
        setUser(null);
        localStorage.removeItem("user");
    };

    return (
        <AuthContext.Provider value={{ user, login, register, logout, loading }}>
            {!loading && children}
        </AuthContext.Provider>
    );
};

import React, { useState, useEffect, useContext } from "react";
import API from "../api/api";
import { AuthContext } from "../context/AuthContext";
import { Users, FileCode2, ShieldAlert, CheckCircle2, AlertTriangle, LogOut, Activity } from "lucide-react";
import { Navigate } from "react-router-dom";

const AdminDashboard = () => {
    const { user, logout } = useContext(AuthContext);
    const [stats, setStats] = useState(null);
    const [loading, setLoading] = useState(true);

    if (user?.role !== "admin") {
        return <Navigate to="/" />;
    }

    useEffect(() => {
        const fetchAdminStats = async () => {
            try {
                const res = await API.get("/admin/stats");
                setStats(res.data);
            } catch (error) {
                console.error("Failed to fetch admin stats:", error);
            } finally {
                setLoading(false);
            }
        };
        fetchAdminStats();
    }, []);

    if (loading) {
        return <div className="flex items-center justify-center min-h-screen text-muted bg-gray-900">Loading System Analytics...</div>;
    }

    if (!stats) {
        return <div className="flex items-center justify-center min-h-screen text-error bg-gray-900">Access Denied or Failed to Load Data</div>;
    }

    const { totalUsers, totalSubmissions, successfulSubmissions, errorSubmissions, commonErrors, recentSubmissions } = stats;

    return (
        <div className="flex-col min-h-screen" style={{ overflow: "hidden" }}>
            {/* Navbar */}
            <header className="flex justify-between items-center" style={{ padding: "0.75rem 2rem", borderBottom: "1px solid var(--glass-border)", background: "var(--glass-bg)", backdropFilter: "blur(10px)" }}>
                <h2 className="text-primary font-bold flex items-center gap-2" style={{ margin: 0, fontSize: "1.25rem" }}>
                    <ShieldAlert size={20} /> Antigravity Admin Center
                </h2>

                <div className="flex items-center gap-6">
                    <span className="text-muted"><strong className="text-white">Admin:</strong> {user?.name}</span>
                    <button onClick={logout} className="btn-primary flex items-center gap-2" style={{ padding: "0.5rem 1rem", background: "rgba(239, 68, 68, 0.2)", color: "var(--error)" }}>
                        <LogOut size={16} /> Logout System
                    </button>
                </div>
            </header>

            <main className="flex-col w-full h-full p-6 animate-fade-in" style={{ height: "calc(100vh - 70px)", overflowY: "auto" }}>
                <h2 className="text-2xl font-bold mb-6 text-white text-opacity-90">Global System Telemetry</h2>

                {/* Top Metrics Cards */}
                <div className="grid grid-cols-4 gap-4 mb-8" style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)" }}>
                    <div className="glass-panel p-6 flex flex-col items-center justify-center border border-primary border-opacity-30">
                        <Users size={32} className="text-primary mb-2" />
                        <h3 className="text-3xl font-bold text-white">{totalUsers}</h3>
                        <p className="text-muted text-sm mt-1">Registered Students</p>
                    </div>
                    <div className="glass-panel p-6 flex flex-col items-center justify-center border border-blue-500 border-opacity-30">
                        <FileCode2 size={32} className="text-blue-400 mb-2" />
                        <h3 className="text-3xl font-bold text-white">{totalSubmissions}</h3>
                        <p className="text-muted text-sm mt-1">Total Network Executions</p>
                    </div>
                    <div className="glass-panel p-6 flex flex-col items-center justify-center border border-success border-opacity-30">
                        <CheckCircle2 size={32} className="text-success mb-2" />
                        <h3 className="text-3xl font-bold text-white">{successfulSubmissions}</h3>
                        <p className="text-muted text-sm mt-1">Global Successes</p>
                    </div>
                    <div className="glass-panel p-6 flex flex-col items-center justify-center border border-error border-opacity-30">
                        <AlertTriangle size={32} className="text-error mb-2" />
                        <h3 className="text-3xl font-bold text-white">{errorSubmissions}</h3>
                        <p className="text-muted text-sm mt-1">Global Failures</p>
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-8" style={{ display: "grid", gridTemplateColumns: "1fr 1fr" }}>

                    {/* Common AI Errors Breakdown */}
                    <div className="glass-panel p-6">
                        <h3 className="text-lg font-semibold border-b border-gray-700 pb-2 mb-4 flex items-center gap-2 text-error text-opacity-90">
                            <ShieldAlert size={20} /> Most Frequent Student Errors
                        </h3>
                        <div className="flex flex-col gap-3">
                            {commonErrors.length > 0 ? commonErrors.map((err, idx) => (
                                <div key={idx} className="flex justify-between items-start p-3 rounded" style={{ background: "rgba(239, 68, 68, 0.05)", borderLeft: "3px solid var(--error)" }}>
                                    <span className="text-sm pr-4 text-white text-opacity-80">{err._id}</span>
                                    <span className="bg-error bg-opacity-20 text-error px-3 py-1 rounded-full text-xs font-bold whitespace-nowrap">{err.count} times</span>
                                </div>
                            )) : <p className="text-muted text-sm">No significant error patterns detected.</p>}
                        </div>
                    </div>

                    {/* Live Student Feed */}
                    <div className="glass-panel p-6">
                        <h3 className="text-lg font-semibold border-b border-gray-700 pb-2 mb-4 flex items-center gap-2 text-blue-400 text-opacity-90">
                            <Activity size={20} /> Live Execution Feed
                        </h3>
                        <div className="flex flex-col gap-2 max-h-96 overflow-y-auto pr-2" style={{ maxHeight: "400px" }}>
                            {recentSubmissions.length > 0 ? recentSubmissions.map(sub => (
                                <div key={sub._id} className="flex flex-col p-3 rounded border border-gray-800" style={{ background: "rgba(0,0,0,0.3)" }}>
                                    <div className="flex justify-between items-center mb-2">
                                        <div className="flex items-center gap-2">
                                            <span className="text-sm font-semibold text-white">{sub.user.name}</span>
                                            <span className="text-xs text-muted">({sub.user.email})</span>
                                        </div>
                                        <span className="text-xs text-muted">{new Date(sub.createdAt).toLocaleTimeString()}</span>
                                    </div>
                                    <div className="flex justify-between items-center">
                                        <span className="capitalize text-xs font-mono bg-gray-800 px-2 py-1 rounded">{sub.language}</span>
                                        <span className={`text-xs font-bold px-2 py-1 rounded ${sub.status === "Success" ? "bg-success bg-opacity-20 text-success" : "bg-error bg-opacity-20 text-error"}`}>
                                            {sub.status}
                                        </span>
                                    </div>
                                </div>
                            )) : <p className="text-muted text-sm">No recent executions in the network.</p>}
                        </div>
                    </div>
                </div>
            </main>
        </div>
    );
};

export default AdminDashboard;

import React, { useState, useContext } from "react";
import { AuthContext } from "../context/AuthContext";
import API from "../api/api";
import CodeEditor from "../components/CodeEditor";
import AnalyticsView from "../components/AnalyticsView";
import { Play, LogOut, CheckCircle, AlertTriangle, Code, Activity } from "lucide-react";

const Dashboard = () => {
    const { user, logout } = useContext(AuthContext);
    const [code, setCode] = useState('print("Hello, World!")');
    const [language, setLanguage] = useState("python");
    const [output, setOutput] = useState("");
    const [isExecuting, setIsExecuting] = useState(false);
    const [errorDetails, setErrorDetails] = useState(null);
    const [activeTab, setActiveTab] = useState("editor");

    const handleLanguageChange = (lang) => {
        setLanguage(lang);
        if (lang === "python") setCode('print("Hello, World!")');
        else if (lang === "javascript") setCode('console.log("Hello, World!");');
        else if (lang === "java") setCode('public class Main {\n  public static void main(String[] args) {\n    System.out.println("Hello, World!");\n  }\n}');
        else if (lang === "cpp") setCode('#include <iostream>\nusing namespace std;\n\nint main() {\n  cout << "Hello, World!" << endl;\n  return 0;\n}');
        else if (lang === "c") setCode('#include <stdio.h>\n\nint main() {\n  printf("Hello, World!\\n");\n  return 0;\n}');
    };

    const handleRunCode = async () => {
        setIsExecuting(true);
        setOutput("");
        setErrorDetails(null);

        try {
            const response = await API.post("/submissions/execute", {
                code,
                language
            });

            const { status, output, rawError, analysis, timeElapsed } = response.data;

            if (status === "Success") {
                setOutput(`Execution Time: ${timeElapsed}ms\n\n${output}`);
            } else {
                // Remove messy ANSI color escape sequences from the terminal error string
                const cleanError = (rawError || "Execution failed without output.").replace(/[\u001b\u009b][[()#;?]*(?:[0-9]{1,4}(?:;[0-9]{0,4})*)?[0-9A-ORZcf-nqry=><]/g, '');
                setOutput(cleanError);
                if (analysis) {
                    setErrorDetails(analysis);
                }
            }
        } catch (err) {
            const errorMsg = err.response?.data?.message || err.message;
            setOutput(`Failed to connect to the execution engine: ${errorMsg}`);
            console.error(err);
        } finally {
            setIsExecuting(false);
        }
    };

    return (
        <div className="flex-col min-h-screen" style={{ overflow: "hidden" }}>
            {/* Navbar */}
            <header className="flex justify-between items-center" style={{ padding: "0.75rem 2rem", borderBottom: "1px solid var(--glass-border)", background: "var(--glass-bg)", backdropFilter: "blur(10px)" }}>
                <h2 className="text-primary font-bold" style={{ margin: 0, fontSize: "1.25rem" }}>Antigravity IDE</h2>

                {/* View Switcher */}
                <div className="flex rounded-lg p-1" style={{ background: "rgba(0,0,0,0.4)" }}>
                    <button
                        onClick={() => setActiveTab("editor")}
                        className="px-4 py-2 rounded flex items-center gap-2 font-medium transition-colors"
                        style={{ background: activeTab === 'editor' ? 'var(--primary)' : 'transparent', color: activeTab === 'editor' ? '#fff' : 'var(--text-muted)' }}>
                        <Code size={18} /> Code Editor
                    </button>
                    <button
                        onClick={() => setActiveTab("analytics")}
                        className="px-4 py-2 rounded flex items-center gap-2 font-medium transition-colors"
                        style={{ background: activeTab === 'analytics' ? 'var(--primary)' : 'transparent', color: activeTab === 'analytics' ? '#fff' : 'var(--text-muted)' }}>
                        <Activity size={18} /> Progress Dashboard
                    </button>
                </div>
                <div className="flex items-center gap-4">
                    <span className="text-muted">Welcome, {user?.name}</span>
                    <button onClick={logout} className="btn-primary flex items-center gap-2" style={{ padding: "0.5rem 1rem", background: "rgba(239, 68, 68, 0.2)", color: "var(--error)" }}>
                        <LogOut size={16} /> Logout
                    </button>
                </div>
            </header>

            {/* Main Split Layout */}
            <main className="flex" style={{ flex: 1, height: "calc(100vh - 70px)" }}>
                {activeTab === "editor" ? (
                    <>
                        {/* Left Pane - Editor */}
                        <div className="flex-col" style={{ flex: "0 0 60%", padding: "1rem", borderRight: "1px solid var(--glass-border)" }}>
                            <div className="glass-panel" style={{ flex: 1, padding: "1rem", display: "flex", flexDirection: "column" }}>
                                <CodeEditor code={code} setCode={setCode} language={language} onLanguageChange={handleLanguageChange} />
                                <div className="mt-4 flex justify-end">
                                    <button onClick={handleRunCode} className="btn-primary flex items-center gap-2" disabled={isExecuting}>
                                        <Play size={16} fill="white" /> {isExecuting ? "Executing..." : "Run Code"}
                                    </button>
                                </div>
                            </div>
                        </div>

                        {/* Right Pane - Output & Analysis */}
                        <div className="flex-col" style={{ flex: "0 0 40%", padding: "1rem", overflowY: "auto" }}>
                            {/* Output Section */}
                            <div className="glass-panel mb-4" style={{ padding: "1rem", minHeight: "200px" }}>
                                <h3 className="text-primary font-semibold mb-2 flex items-center gap-2 border-b border-gray-700 pb-2">
                                    <span style={{ fontSize: "1.2rem", borderBottom: "1px solid var(--glass-border)", display: "block", background: "none" }}>Execution Output</span>
                                </h3>
                                <pre className="mt-4 p-4 text-sm font-mono" style={{ background: "rgba(0,0,0,0.5)", borderRadius: "8px", minHeight: "100px", color: errorDetails ? "var(--error)" : "var(--text-main)", whiteSpace: "pre-wrap" }}>
                                    {output || "Run your code to see the output..."}
                                </pre>
                            </div>

                            {/* AI Analysis Section */}
                            <div className="glass-panel" style={{ padding: "1rem", flex: 1 }}>
                                <h3 className="text-primary font-semibold mb-2 flex items-center gap-2 border-b border-gray-700 pb-2">
                                    Analysis & Feedback
                                </h3>
                                <div className="mt-4 p-4" style={{ background: "rgba(0,0,0,0.3)", borderRadius: "8px", minHeight: "150px" }}>
                                    {errorDetails ? (
                                        <div className="animate-fade-in">
                                            <div className="flex items-center gap-2 mb-2" style={{ color: "var(--error)" }}>
                                                <AlertTriangle size={20} /> <strong style={{ fontSize: "1.1rem" }}>Error Detected!</strong>
                                            </div>
                                            <p className="mb-2"><strong>Line:</strong> {errorDetails.line}</p>
                                            <p className="mb-2"><strong>Issue:</strong> {errorDetails.explanation}</p>
                                            <div className="p-3 mt-4" style={{ background: "rgba(59, 130, 246, 0.1)", borderLeft: "4px solid var(--primary)", borderRadius: "4px" }}>
                                                <strong>Suggested Fix:</strong> <br /> {errorDetails.suggestedAction}
                                            </div>
                                        </div>
                                    ) : (
                                        <div className="flex flex-col items-center justify-center h-full text-muted opacity-60">
                                            <CheckCircle size={48} className="mb-2 text-success" />
                                            <p>Code looks good! No active errors detected.</p>
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    </>
                ) : (
                    <AnalyticsView />
                )}
            </main>
        </div>
    );
};

export default Dashboard;
